const body = $input.first().json;

let githubUrl = String(body.github_url || body.githubUrl || body.repo || '').trim();
let branch = String(body.branch || body.ref || 'main').trim();

if (branch.startsWith('refs/heads/')) {
  branch = branch.replace('refs/heads/', '');
}

if (!githubUrl) {
  throw new Error('Set github_url in node "GitHub URL + Branch"');
}
if (!branch) {
  throw new Error('Set branch in node "GitHub URL + Branch"');
}

let cloneUrl = githubUrl.replace(/\/+$/, '');
if (!cloneUrl.endsWith('.git')) {
  cloneUrl = cloneUrl + '.git';
}
if (!/^https?:\/\//i.test(cloneUrl) && cloneUrl.includes('github.com')) {
  cloneUrl = 'https://' + cloneUrl.replace(/^\/+/, '');
}

const deployApi = body.deploy_api !== false && body.deploy_api !== 0 && body.deploy_api !== '0';
const deployWeb = body.deploy_web !== false && body.deploy_web !== 0 && body.deploy_web !== '0';

return [{
  json: {
    github_url: githubUrl,
    clone_url: cloneUrl,
    branch,
    deploy_api: deployApi,
    deploy_web: deployWeb,
    requested_at: new Date().toISOString(),
  }
}];

